from dataclasses import dataclass, field
from typing import Any, Dict

token_usage: type["TokenUsage"] = None  # Will be defined below

class TokenUsage:
    def __init__(self, input_tokens: int, output_tokens: int, total_tokens: int):
        self.input_tokens = input_tokens
        self.output_tokens = output_tokens
        self.total_tokens = total_tokens

@dataclass
class Answer:
    text: str | None = None
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        if self.text is None:
            raise ValueError("Answer text cannot be None")

    def add_token_usage(self, token_usage: "TokenUsage") -> None:
        if 'token_usage' not in self.metadata:
            self.metadata['token_usage'] = {
                'input': 0,
                'output': 0,
                'total': 0
            }

        existing = self.metadata['token_usage']
        self.metadata['token_usage'] = {
            'input': existing['input'] + token_usage.input_tokens,
            'output': existing['output'] + token_usage.output_tokens,
            'total': existing['total'] + token_usage.total_tokens
        }

    def get_token_usage(self) -> "TokenUsage":
        if 'token_usage' not in self.metadata:
            return TokenUsage(0, 0, 0)

        usage = self.metadata['token_usage']
        return TokenUsage(
            usage['input'],
            usage['output'],
            usage['total']
        )

